import clsx from 'clsx';
import React from 'react';
import { getTreeNodeConfigPath } from '../../tree';
import { getCascaderLabel, useCascaderMenuCssScope } from '../common';
import type { CascaderProps } from '../interface';
import type { Required } from 'utility-types';
import type { DoublyTreeNode } from '../../tree';

export function useOptions(
  props: Required<
    Pick<CascaderProps, 'filterOption' | 'filterResultRenderer' | 'filterResultSorter'>,
    'filterOption'
  > & { inputValue: string; doublyTreeNodeList: DoublyTreeNode[] },
) {
  const { inputValue, filterResultRenderer, doublyTreeNodeList, filterOption, filterResultSorter } = props;
  const cssScope = useCascaderMenuCssScope();
  const searching = Boolean(inputValue);

  /**
   * 搜索结果选项的渲染
   */
  const labelRenderer = React.useMemo(() => {
    if (searching && filterResultRenderer) {
      // 如果有搜索值并且设置了自定义render, 使用自定义 labelRenderer
      return (node: DoublyTreeNode) => filterResultRenderer(getTreeNodeConfigPath(node), inputValue);
    }
    return (node: DoublyTreeNode) =>
      getCascaderLabel(node, {
        highlightMarkClassName: clsx(!node.__node__.disabled && cssScope('__option__label-highlight')),
        cascaded: searching,
      });
  }, [cssScope, filterResultRenderer, inputValue, searching]);

  /**
   * ======== Search Dropdown ========
   */
  const treeNodeList = React.useMemo(() => {
    if (!searching) {
      return doublyTreeNodeList;
    }
    const result = doublyTreeNodeList.filter(node => filterOption(inputValue, node));

    if (filterResultSorter) {
      result.sort((doublyNode1, doublyNode2) =>
        filterResultSorter(getTreeNodeConfigPath(doublyNode1), getTreeNodeConfigPath(doublyNode2), inputValue),
      );
    }
    return result;
  }, [searching, doublyTreeNodeList, filterResultSorter, filterOption, inputValue]);

  return {
    searching,
    labelRenderer,
    treeNodeList,
  };
}
